self.onmessage=async t=>{const{id:r,type:e,payload:s}=t.data;try{if("sha256"===e){const t=s.buffer,e=await async function(t){const r=await crypto.subtle.digest("SHA-256",t);return Array.from(new Uint8Array(r)).map(t=>t.toString(16).padStart(2,"0")).join("")}(t);return void self.postMessage({id:r,ok:!0,result:e},[t])}throw new Error("unknown file op")}catch(a){self.postMessage({id:r,ok:!1,error:String(a?.message||a)})}};
